{
  "mode": "All",
  "displayName": "Subscriptions must have a paid support plan",
  "description": "Flags subscriptions with only the Basic (free) support plan.",
  "policyRule": {
    "if": {
      "allOf": [
        {
          "field": "type",
          "equals": "Microsoft.Resources/subscriptions"
        },
        {
          "not": {
            "field": "Microsoft.Support/supportPlanTypes/planType",
            "in": ["Developer", "Standard", "ProfessionalDirect", "Premier"]
          }
        }
      ]
    },
    "then": {
      "effect": "audit"
    }
  }
}
